    /**
     * Sets $this->container[$variableName] to the given data or to the given default Value; if $variableName
     * is nullable and its value is set to null in the $fields array, then mark it as "set to null" in the
     * $this->openAPINullablesSetToNull array
     *
     * @param string $variableName
     * @param array  $fields
     * @param mixed  $defaultValue
     */
    private function setIfExists(string $variableName, array $fields, $defaultValue): void
    {
        if (self::isNullable($variableName) && array_key_exists($variableName, $fields) && is_null($fields[$variableName])) {
            $this->openAPINullablesSetToNull[] = $variableName;
        }

        $this->container[$variableName] = $fields[$variableName] ?? $defaultValue;
    }

    /**
     * Show all the invalid properties with reasons.
     *
     * @return array invalid properties with reasons
     */
    public function listInvalidProperties()
    {
        $invalidProperties = [];

        
        
        
        
        if (!is_null($this->container['cores']) && ($this->container['cores'] > 8192)) {
            $invalidProperties[] = "invalid value for 'cores', must be smaller than or equal to 8192.";
        }

        if (!is_null($this->container['cores']) && ($this->container['cores'] < 1)) {
            $invalidProperties[] = "invalid value for 'cores', must be bigger than or equal to 1.";
        }

        
        if (!is_null($this->container['cpulimit']) && ($this->container['cpulimit'] > 8192)) {
            $invalidProperties[] = "invalid value for 'cpulimit', must be smaller than or equal to 8192.";
        }

        if (!is_null($this->container['cpulimit']) && ($this->container['cpulimit'] < 0)) {
            $invalidProperties[] = "invalid value for 'cpulimit', must be bigger than or equal to 0.";
        }

        
        if (!is_null($this->container['cpuunits']) && ($this->container['cpuunits'] > 500000)) {
            $invalidProperties[] = "invalid value for 'cpuunits', must be smaller than or equal to 500000.";
        }

        if (!is_null($this->container['cpuunits']) && ($this->container['cpuunits'] < 0)) {
            $invalidProperties[] = "invalid value for 'cpuunits', must be bigger than or equal to 0.";
        }

        
        
        if (!is_null($this->container['description']) && (mb_strlen($this->container['description']) > 8192)) {
            $invalidProperties[] = "invalid value for 'description', the character length must be smaller than or equal to 8192.";
        }

        
        if ($this->container['dev0'] === null) {
            $invalidProperties[] = "'dev0' can't be null";
